$errors = @()Get-ChildItem -Path "*.cs" -Recurse | ForEach-Object {    $content = Get-Content $_.FullName    $lineNumber = 0    foreach ($line in $content) {        $lineNumber++                # Catch ??= operator        if ($line -match '\?\?=') {            Write-Host "$($_.FullName)($lineNumber,$lineNumber): error CS1234: Null coalescing assignment (??=) is not allowed to keep Il2Cpp happy"            $errors += $true        }                # Catch ?. in assignments        if ($line -match '(?:\?\.\w+)+\.?\s*=') {            Write-Host "$($_.FullName)($lineNumber,$lineNumber): error CS1235: Null conditional assignment (?.) is not allowed to keep Il2Cpp happy"            $errors += $true        }                # Catch ?. in comparisons        if ($line -match '(?:\?\.\w+)+\.?\s*==') {            Write-Host "$($_.FullName)($lineNumber,$lineNumber): error CS1236: Null conditional in comparison (?.) is not allowed to keep Il2Cpp happy"            $errors += $true        }                # Catch ?. in any other comparison operators        if ($line -match '(?:\?\.\w+)+\.?\s*[!=<>]=?') {            Write-Host "$($_.FullName)($lineNumber,$lineNumber): error CS1236: Null conditional in comparison (?.) is not allowed to keep Il2Cpp happy"            $errors += $true        }    }}if ($errors.Count -gt 0) {    Write-Host "`nFound $($errors.Count) Il2Cpp-incompatible null operators. Use explicit null checks instead." -ForegroundColor Red    exit 1}